using System.ComponentModel;
using System.Text.Json;
using Microsoft.Extensions.Logging;
using ModelContextProtocol.Server;

/// <summary>
/// MCP tools that wrap the JSONPlaceholder REST API.
/// Uses constructor injection for HttpClient and ILogger.
/// </summary>
[McpServerToolType]
public class ApiTools(HttpClient httpClient, ILogger<ApiTools> logger)
{
    private static readonly JsonSerializerOptions JsonOptions = new() { WriteIndented = true };

    [McpServerTool, Description("Get a post by its ID from the REST API.")]
    public async Task<string> GetPost(
        [Description("The numeric ID of the post (1-100)")] int id,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Fetching post {Id}", id);
        var response = await httpClient.GetAsync($"/posts/{id}", cancellationToken);
        response.EnsureSuccessStatusCode();
        var json = await response.Content.ReadAsStringAsync(cancellationToken);
        return json;
    }

    [McpServerTool, Description("List posts, optionally filtered by user ID.")]
    public async Task<string> ListPosts(
        [Description("Filter posts by this user ID (optional)")] int? userId = null,
        CancellationToken cancellationToken = default)
    {
        var url = userId.HasValue ? $"/posts?userId={userId}" : "/posts";
        logger.LogInformation("Listing posts from {Url}", url);
        var response = await httpClient.GetAsync(url, cancellationToken);
        response.EnsureSuccessStatusCode();
        var json = await response.Content.ReadAsStringAsync(cancellationToken);
        return json;
    }

    [McpServerTool, Description("Get all comments for a specific post.")]
    public async Task<string> GetComments(
        [Description("The post ID to retrieve comments for")] int postId,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Fetching comments for post {PostId}", postId);
        var response = await httpClient.GetAsync($"/posts/{postId}/comments", cancellationToken);
        response.EnsureSuccessStatusCode();
        var json = await response.Content.ReadAsStringAsync(cancellationToken);
        return json;
    }

    [McpServerTool(Destructive = false, ReadOnly = true),
     Description("Search for users by name or username.")]
    public async Task<string> SearchUsers(
        [Description("Search query to match against user name or username")] string query,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Searching users with query '{Query}'", query);
        var response = await httpClient.GetAsync("/users", cancellationToken);
        response.EnsureSuccessStatusCode();
        var json = await response.Content.ReadAsStringAsync(cancellationToken);
        using var doc = JsonDocument.Parse(json);
        var matches = doc.RootElement.EnumerateArray()
            .Where(u =>
                (u.GetProperty("name").GetString()?.Contains(query, StringComparison.OrdinalIgnoreCase) ?? false) ||
                (u.GetProperty("username").GetString()?.Contains(query, StringComparison.OrdinalIgnoreCase) ?? false))
            .Select(u => u.GetRawText());
        return $"[{string.Join(",", matches)}]";
    }
}

