      Description("Search for users by name or username.")]
     public async Task<string> SearchUsers(
         [Description("Search query to match against user name or username")] string query,
         CancellationToken cancellationToken = default)
     {
         logger.LogInformation("Searching users with query '{Query}'", query);
         var response = await httpClient.GetAsync("/users", cancellationToken);
         response.EnsureSuccessStatusCode();
         var json = await response.Content.ReadAsStringAsync(cancellationToken);
         using var doc = JsonDocument.Parse(json);
         var matches = doc.RootElement.EnumerateArray()
             .Where(u =>
                 (u.GetProperty("name").GetString()?.Contains(query, StringComparison.OrdinalIgnoreCase) ?? false) ||
                 (u.GetProperty("username").GetString()?.Contains(query, StringComparison.OrdinalIgnoreCase) ?? false))
             .Select(u => u.GetRawText());
         return $"[{string.Join(",", matches)}]";
     }
